using Microsoft.AspNetCore.Mvc;
using OneOf;
using System.ComponentModel.DataAnnotations;

// Models
public enum OrderStatus
{
    Pending = 0,
    Processing = 1,
    Shipped = 2,
    Delivered = 3,
    Cancelled = 4
}

public record OrderItem(
    Guid Id,
    string ProductName,
    int Quantity,
    decimal UnitPrice
);

public record Order(
    Guid Id,
    string CustomerEmail,
    string CustomerName,
    decimal TotalAmount,
    OrderStatus Status,
    DateTime CreatedAt,
    DateTime? ShippedAt,
    List<OrderItem> Items
);

public record OrderQueryParameters(
    [Range(1, int.MaxValue)] int Page = 1,
    [Range(1, 100)] int PageSize = 20,
    string? CustomerEmail = null,
    string? CustomerName = null,
    OrderStatus? Status = null,
    DateTime? CreatedFrom = null,
    DateTime? CreatedTo = null,
    decimal? MinAmount = null,
    decimal? MaxAmount = null,
    string? SortBy = "CreatedAt",
    string? SortOrder = "desc"
);

public record PagedResult<T>(
    List<T> Items,
    int TotalCount,
    int Page,
    int PageSize,
    int TotalPages
);

// OneOf Result Types
public record OrderNotFound(Guid Id);
public record ValidationError(Dictionary<string, string[]> Errors);
public record OrderCreated(Order Order);

// Services
public interface IOrderService
{
    Task<OneOf<PagedResult<Order>, ValidationError>> GetOrdersAsync(OrderQueryParameters parameters);
    Task<OneOf<Order, OrderNotFound>> GetOrderByIdAsync(Guid id);
    Task<OneOf<OrderCreated, ValidationError>> CreateOrderAsync(CreateOrderRequest request);
    Task<OneOf<Order, OrderNotFound, ValidationError>> UpdateOrderStatusAsync(Guid id, UpdateOrderStatusRequest request);
}

public record CreateOrderRequest(
    [Required] string CustomerEmail,
    [Required] string CustomerName,
    [Range(0.01, double.MaxValue)] decimal TotalAmount,
    List<CreateOrderItemRequest> Items
);

public record CreateOrderItemRequest(
    [Required] string ProductName,
    [Range(1, int.MaxValue)] int Quantity,
    [Range(0.01, double.MaxValue)] decimal UnitPrice
);

public record UpdateOrderStatusRequest(
    [Required] OrderStatus Status,
    DateTime? ShippedAt = null
);

public class OrderService : IOrderService
{
    private readonly List<Order> _orders = new();
    private readonly object _lock = new();

    public OrderService()
    {
        // Seed data
        SeedData();
    }

    private void SeedData()
    {
        var orderId1 = Guid.NewGuid();
        var orderId2 = Guid.NewGuid();
        var orderId3 = Guid.NewGuid();

        _orders.AddRange(new[]
        {
            new Order(
                orderId1,
                "john@example.com",
                "John Doe",
                299.99m,
                OrderStatus.Delivered,
                DateTime.UtcNow.AddDays(-10),
                DateTime.UtcNow.AddDays(-5),
                new List<OrderItem>
                {
                    new(Guid.NewGuid(), "Laptop", 1, 299.99m)
                }
            ),
            new Order(
                orderId2,
                "jane@example.com",
                "Jane Smith",
                149.50m,
                OrderStatus.Processing,
                DateTime.UtcNow.AddDays(-3),
                null,
                new List<OrderItem>
                {
                    new(Guid.NewGuid(), "Headphones", 2, 49.99m),
                    new(Guid.NewGuid(), "Mouse", 1, 49.52m)
                }
            ),
            new Order(
                orderId3,
                "bob@example.com",
                "Bob Wilson",
                599.00m,
                OrderStatus.Pending,
                DateTime.UtcNow.AddDays(-1),
                null,
                new List<OrderItem>
                {
                    new(Guid.NewGuid(), "Monitor", 1, 599.00m)
                }
            )
        });
    }

    public Task<OneOf<PagedResult<Order>, ValidationError>> GetOrdersAsync(OrderQueryParameters parameters)
    {
        var errors = ValidateParameters(parameters);
        if (errors.Count > 0)
        {
            return Task.FromResult<OneOf<PagedResult<Order>, ValidationError>>(
                new ValidationError(errors));
        }

        lock (_lock)
        {
            var query = _orders.AsQueryable();

            // Filtering
            if (!string.IsNullOrEmpty(parameters.CustomerEmail))
            {
                query = query.Where(o => o.CustomerEmail.Contains(parameters.CustomerEmail, StringComparison.OrdinalIgnoreCase));
            }

            if (!string.IsNullOrEmpty(parameters.CustomerName))
            {
                query = query.Where(o => o.CustomerName.Contains(parameters.CustomerName, StringComparison.OrdinalIgnoreCase));
            }

            if (parameters.Status.HasValue)
            {
                query = query.Where(o => o.Status == parameters.Status.Value);
            }

            if (parameters.CreatedFrom.HasValue)
            {
                query = query.Where(o => o.CreatedAt >= parameters.CreatedFrom.Value);
            }

            if (parameters.CreatedTo.HasValue)
            {
                query = query.Where(o => o.CreatedAt <= parameters.CreatedTo.Value);
            }

            if (parameters.MinAmount.HasValue)
            {
                query = query.Where(o => o.TotalAmount >= parameters.MinAmount.Value);
            }

            if (parameters.MaxAmount.HasValue)
            {
                query = query.Where(o => o.TotalAmount <= parameters.MaxAmount.Value);
            }

            // Sorting
            var sortBy = parameters.SortBy?.ToLower() ?? "createdat";
            var sortDesc = parameters.SortOrder?.ToLower() != "asc";

            query = (sortBy, sortDesc) switch
            {
                ("createdat", true) => query.OrderByDescending(o => o.CreatedAt),
                ("createdat", false) => query.OrderBy(o => o.CreatedAt),
                ("totalamount", true) => query.OrderByDescending(o => o.TotalAmount),
                ("totalamount", false) => query.OrderBy(o => o.TotalAmount),
                ("customername", true) => query.OrderByDescending(o => o.CustomerName),
                ("customername", false) => query.OrderBy(o => o.CustomerName),
                ("status", true) => query.OrderByDescending(o => o.Status),
                ("status", false) => query.OrderBy(o => o.Status),
                _ => query.OrderByDescending(o => o.CreatedAt)
            };

            var totalCount = query.Count();
            var totalPages = (int)Math.Ceiling(totalCount / (double)parameters.PageSize);

            var items = query
                .Skip((parameters.Page - 1) * parameters.PageSize)
                .Take(parameters.PageSize)
                .ToList();

            var result = new PagedResult<Order>(items, totalCount, parameters.Page, parameters.PageSize, totalPages);

            return Task.FromResult<OneOf<PagedResult<Order>, ValidationError>>(result);
        }
    }

    public Task<OneOf<Order, OrderNotFound>> GetOrderByIdAsync(Guid id)
    {
        lock (_lock)
        {
            var order = _orders.FirstOrDefault(o => o.Id == id);
            if (order == null)
            {
                return Task.FromResult<OneOf<Order, OrderNotFound>>(new OrderNotFound(id));
            }
            return Task.FromResult<OneOf<Order, OrderNotFound>>(order);
        }
    }

    public Task<OneOf<OrderCreated, ValidationError>> CreateOrderAsync(CreateOrderRequest request)
    {
        var errors = ValidateCreateRequest(request);
        if (errors.Count > 0)
        {
            return Task.FromResult<OneOf<OrderCreated, ValidationError>>(
                new ValidationError(errors));
        }

        lock (_lock)
        {
            var orderItems = request.Items.Select(i => new OrderItem(
                Guid.NewGuid(),
                i.ProductName,
                i.Quantity,
                i.UnitPrice
            )).ToList();

            var order = new Order(
                Guid.NewGuid(),
                request.CustomerEmail,
                request.CustomerName,
                request.TotalAmount,
                OrderStatus.Pending,
                DateTime.UtcNow,
                null,
                orderItems
            );

            _orders.Add(order);

            return Task.FromResult<OneOf<OrderCreated, ValidationError>>(
                new OrderCreated(order));
        }
    }

    public Task<OneOf<Order, OrderNotFound, ValidationError>> UpdateOrderStatusAsync(Guid id, UpdateOrderStatusRequest request)
    {
        lock (_lock)
        {
            var orderIndex = _orders.FindIndex(o => o.Id == id);
            if (orderIndex == -1)
            {
                return Task.FromResult<OneOf<Order, OrderNotFound, ValidationError>>(
                    new OrderNotFound(id));
            }

            var order = _orders[orderIndex];
            var updatedOrder = order with
            {
                Status = request.Status,
                ShippedAt = request.ShippedAt ?? order.ShippedAt
            };

            _orders[orderIndex] = updatedOrder;

            return Task.FromResult<OneOf<Order, OrderNotFound, ValidationError>>(updatedOrder);
        }
    }

    private Dictionary<string, string[]> ValidateParameters(OrderQueryParameters parameters)
    {
        var errors = new Dictionary<string, string[]>();

        if (parameters.CreatedFrom.HasValue && parameters.CreatedTo.HasValue &&
            parameters.CreatedFrom > parameters.CreatedTo)
        {
            errors["CreatedFrom"] = new[] { "CreatedFrom must be before or equal to CreatedTo" };
        }

        if (parameters.MinAmount.HasValue && parameters.MaxAmount.HasValue &&
            parameters.MinAmount > parameters.MaxAmount)
        {
            errors["MinAmount"] = new[] { "MinAmount must be less than or equal to MaxAmount" };
        }

        return errors;
    }

    private Dictionary<string, string[]> ValidateCreateRequest(CreateOrderRequest request)
    {
        var errors = new Dictionary<string, string[]>();

        if (string.IsNullOrWhiteSpace(request.CustomerEmail))
        {
            errors["CustomerEmail"] = new[] { "CustomerEmail is required" };
        }
        else if (!request.CustomerEmail.Contains('@'))
        {
            errors["CustomerEmail"] = new[] { "CustomerEmail must be a valid email address" };
        }

        if (request.Items == null || request.Items.Count == 0)
        {
            errors["Items"] = new[] { "At least one order item is required" };
        }

        return errors;
    }
}

// Program
var builder = WebApplication.CreateBuilder(args);

// Add services
builder.Services.AddScoped<IOrderService, OrderService>();

var app = builder.Build();

// Exception handler
app.UseExceptionHandler(err => err.Run(async ctx =>
{
    ctx.Response.ContentType = "application/problem+json";
    await ctx.Response.WriteAsJsonAsync(new ProblemDetails
    {
        Title = "Server Error",
        Status = 500,
        Detail = "An unexpected error occurred"
    });
}));

// GET /orders - List with pagination, filtering, sorting
app.MapGet("/orders", async (
    [FromServices] IOrderService orderService,
    [AsParameters] OrderQueryParameters parameters) =>
{
    var result = await orderService.GetOrdersAsync(parameters);

    return result.Match(
        paged => Results.Ok(paged),
        validation => Results.ValidationProblem(validation.Errors)
    );
});

// GET /orders/{id} - Get single order
app.MapGet("/orders/{id:guid}", async (
    [FromServices] IOrderService orderService,
    Guid id) =>
{
    var result = await orderService.GetOrderByIdAsync(id);

    return result.Match<Order, OrderNotFound, IResult>(
        order => Results.Ok(order),
        notFound => Results.NotFound(new { Message = $"Order with ID {notFound.Id} not found" })
    );
});

// POST /orders - Create new order
app.MapPost("/orders", async (
    [FromServices] IOrderService orderService,
    [FromBody] CreateOrderRequest request) =>
{
    var result = await orderService.CreateOrderAsync(request);

    return result.Match<OrderCreated, ValidationError, IResult>(
        created => Results.Created($"/orders/{created.Order.Id}", created.Order),
        validation => Results.ValidationProblem(validation.Errors)
    );
});

// PATCH /orders/{id}/status - Update order status
app.MapPatch("/orders/{id:guid}/status", async (
    [FromServices] IOrderService orderService,
    Guid id,
    [FromBody] UpdateOrderStatusRequest request) =>
{
    var result = await orderService.UpdateOrderStatusAsync(id, request);

    return result.Match<Order, OrderNotFound, ValidationError, IResult>(
        order => Results.Ok(order),
        notFound => Results.NotFound(new { Message = $"Order with ID {notFound.Id} not found" }),
        validation => Results.ValidationProblem(validation.Errors)
    );
});

app.Run();

using System;
using System.Collections.Generic;
using System.ComponentModel.DataAnnotations;
using System.Linq;
using System.Security.Claims;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Builder;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using OneOf;

// Enums
public enum OrderStatus { Pending, Confirmed, Shipped, Delivered, Cancelled }
public enum CustomerRole { Customer, PremiumCustomer, Admin }

// Domain Models
public record OrderItem(Guid ProductId, string ProductName, int Quantity, decimal UnitPrice);

public record Order(
    Guid OrderId,
    Guid CustomerId,
    IReadOnlyList<OrderItem> Items,
    decimal TotalAmount,
    OrderStatus Status,
    DateTimeOffset CreatedAt,
    string ShippingAddress
