// Repository implementation
public class InMemoryPatientRepository : IPatientRepository
{
    private readonly ConcurrentDictionary<Guid, Patient> _patients = new();

    public Task<IEnumerable<Patient>> GetAllAsync()
    {
        return Task.FromResult(_patients.Values.AsEnumerable());
    }

    public Task<Patient?> GetByIdAsync(Guid id)
    {
        _patients.TryGetValue(id, out var patient);
        return Task.FromResult(patient);
    }

    public Task<Patient> CreateAsync(CreatePatientRequest request)
    {
        var patient = new Patient(
            Guid.NewGuid(),
            request.FirstName,
            request.LastName,
            request.DateOfBirth,
            request.MedicalRecordNumber,
            request.Email,
            request.Status
        );
        _patients.TryAdd(patient.Id, patient);
        return Task.FromResult(patient);
    }

    public Task<Patient?> UpdateAsync(Guid id, UpdatePatientRequest request)
    {
        if (!_patients.TryGetValue(id, out var existingPatient))
        {
            return Task.FromResult<Patient?>(null);
        }

        var updatedPatient = new Patient(
            id,
            request.FirstName,
            request.LastName,
            request.DateOfBirth,
            request.MedicalRecordNumber,
            request.Email,
            request.Status
        );

        _patients.TryUpdate(id, updatedPatient, existingPatient);
        return Task.FromResult<Patient?>(updatedPatient);
    }

    public Task<bool> DeleteAsync(Guid id)
    {
        var deleted = _patients.TryRemove(id, out _);
        return Task.FromResult(deleted);
    }
}

