    Task<OneOf<NotFoundError>> DeletePatientAsync(Guid id);
}

// Service implementation
public class PatientService : IPatientService
{
    private readonly IPatientRepository _repository;

    public PatientService(IPatientRepository repository)
    {
        _repository = repository;
    }

    public async Task<OneOf<Patient, NotFoundError>> GetPatientByIdAsync(Guid id)
    {
        var patient = await _repository.GetByIdAsync(id);
        if (patient is null)
        {
            return new NotFoundError(id, $"Patient with ID {id} not found");
        }
        return patient;
    }

    public async Task<IEnumerable<Patient>> GetAllPatientsAsync()
    {
        return await _repository.GetAllAsync();
    }

    public async Task<OneOf<Patient, ValidationError>> CreatePatientAsync(CreatePatientRequest request)
    {
        var validationErrors = ValidateCreateRequest(request);
        if (validationErrors.Count > 0)
        {
            return new ValidationError(validationErrors);
        }

        var patient = await _repository.CreateAsync(request);
        return patient;
    }

    public async Task<OneOf<Patient, NotFoundError, ValidationError>> UpdatePatientAsync(Guid id, UpdatePatientRequest request)
    {
        var existingPatient = await _repository.GetByIdAsync(id);
        if (existingPatient is null)
        {
            return new NotFoundError(id, $"Patient with ID {id} not found");
        }

        var validationErrors = ValidateUpdateRequest(request);
        if (validationErrors.Count > 0)
        {
            return new ValidationError(validationErrors);
        }

        var updatedPatient = await _repository.UpdateAsync(id, request);
        return updatedPatient!;
    }

    public async Task<OneOf<NotFoundError>> DeletePatientAsync(Guid id)
    {
        var deleted = await _repository.DeleteAsync(id);
        if (!deleted)
        {
            return new NotFoundError(id, $"Patient with ID {id} not found");
        }
        return default;
    }

    private Dictionary<string, string[]> ValidateCreateRequest(CreatePatientRequest request)
    {
        var errors = new Dictionary<string, string[]>();

        if (request.DateOfBirth >= DateTime.UtcNow)
        {
            errors[nameof(request.DateOfBirth)] = new[] { "DateOfBirth must be in the past" };
        }

        return errors;
    }

    private Dictionary<string, string[]> ValidateUpdateRequest(UpdatePatientRequest request)
    {
        var errors = new Dictionary<string, string[]>();

        if (request.DateOfBirth >= DateTime.UtcNow)
        {
            errors[nameof(request.DateOfBirth)] = new[] { "DateOfBirth must be in the past" };
        }

        return errors;
    }
}

// OneOf discriminated union implementation
public readonly struct OneOf<T0, T1>
{
    private readonly T0? _value0;
    private readonly T1? _value1;
    private readonly int _index;

    private OneOf(T0 value) { _value0 = value; _value1 = default; _index = 0; }
    private OneOf(T1 value) { _value0 = default; _value1 = value; _index = 1; }

    public static implicit operator OneOf<T0, T1>(T0 value) => new(value);
    public static implicit operator OneOf<T0, T1>(T1 value) => new(value);

    public TResult Match<TResult>(Func<T0, TResult> f0, Func<T1, TResult> f1)
        => _index switch
        {
            0 => f0(_value0!),
            1 => f1(_value1!),
            _ => throw new InvalidOperationException()
        };
}

public readonly struct OneOf<T0, T1, T2>
{
    private readonly T0? _value0;
    private readonly T1? _value1;
    private readonly T2? _value2;
    private readonly int _index;

    private OneOf(T0 value) { _value0 = value; _value1 = default; _value2 = default; _index = 0; }
    private OneOf(T1 value) { _value0 = default; _value1 = value; _value2 = default; _index = 1; }
    private OneOf(T2 value) { _value0 = default; _value1 = default; _value2 = value; _index = 2; }

    public static implicit operator OneOf<T0, T1, T2>(T0 value) => new(value);
    public static implicit operator OneOf<T0, T1, T2>(T1 value) => new(value);
    public static implicit operator OneOf<T0, T1, T2>(T2 value) => new(value);

    public TResult Match<TResult>(Func<T0, TResult> f0, Func<T1, TResult> f1, Func<T2, TResult> f2)
        => _index switch
        {
            0 => f0(_value0!),
            1 => f1(_value1!),
            2 => f2(_value2!),
            _ => throw new InvalidOperationException()
        };
}

// Program.cs
public class Program
{
    public static void Main(string[] args)
    {
        var builder = WebApplication.CreateBuilder(args);

        // Register services
        builder.Services.AddSingleton<IPatientRepository, InMemoryPatientRepository>();
        builder.Services.AddScoped<IPatientService, PatientService>();

        var app = builder.Build();

        // Exception handler
        app.UseExceptionHandler(err => err.Run(async ctx =>
        {
            ctx.Response.ContentType = "application/problem+json";
            await ctx.Response.WriteAsJsonAsync(new ProblemDetails
            {
                Title = "Server Error",
                Status = 500,
                Detail = "An unexpected error occurred while processing the request"
            });
        }));

        // GET /patients - Get all patients
        app.MapGet("/patients", async (IPatientService service) =>
        {
            var patients = await service.GetAllPatientsAsync();
            return Results.Ok(patients);
        });

        // GET /patients/{id} - Get patient by ID
        app.MapGet("/patients/{id:guid}", async (Guid id, IPatientService service) =>
        {
            var result = await service.GetPatientByIdAsync(id);
            return result.Match<Patient, NotFoundError, IResult>(
                patient => Results.Ok(patient),
                error => Results.NotFound(new { error.Id, error.Message })
            );
        });

        // POST /patients - Create new patient
        app.MapPost("/patients", async (CreatePatientRequest request, IPatientService service) =>
        {
            var result = await service.CreatePatientAsync(request);
            return result.Match<Patient, ValidationError, IResult>(
                patient => Results.Created($"/patients/{patient.Id}", patient),
                error => Results.ValidationProblem(error.Errors)
            );
        });

        // PUT /patients/{id} - Update patient
        app.MapPut("/patients/{id:guid}", async (Guid id, UpdatePatientRequest request, IPatientService service) =>
        {
            var result = await service.UpdatePatientAsync(id, request);
            return result.Match<Patient, NotFoundError, ValidationError, IResult>(
                patient => Results.Ok(patient),
                error => Results.NotFound(new { error.Id, error.Message }),
                error => Results.ValidationProblem(error.Errors)
            );
        });

        // DELETE /patients/{id} - Delete patient
        app.MapDelete("/patients/{id:guid}", async (Guid id, IPatientService service) =>
        {
            var result = await service.DeletePatientAsync(id);
            return result.Match<OneOf<NotFoundError>, IResult>(
                _ => Results.NoContent(),
                error => Results.NotFound(new { error.Id, error.Message })
            );
        });

        app.Run();
    }
}

