    {
        var order = _orders.FirstOrDefault(o => o.Id == id);
        return Task.FromResult(order is not null
            ? new OneOf<TradeOrder, OrderNotFound>(order)
            : new OrderNotFound(id));
    }

    public Task<PaginatedResult<TradeOrder>> GetPagedAsync(
        PaginationQuery pagination,
        TradeOrderFilter? filter,
        TradeOrderSort? sort)
    {
        var query = _orders.AsEnumerable();

        if (filter is not null)
        {
            if (!string.IsNullOrWhiteSpace(filter.Symbol))
                query = query.Where(o => o.Symbol.Equals(filter.Symbol, StringComparison.OrdinalIgnoreCase));

            if (!string.IsNullOrWhiteSpace(filter.Side))
                query = query.Where(o => o.Side.Equals(filter.Side, StringComparison.OrdinalIgnoreCase));

            if (!string.IsNullOrWhiteSpace(filter.Status))
                query = query.Where(o => o.Status.Equals(filter.Status, StringComparison.OrdinalIgnoreCase));

            if (filter.FromDate.HasValue)
                query = query.Where(o => o.CreatedAt >= filter.FromDate.Value);

            if (filter.ToDate.HasValue)
                query = query.Where(o => o.CreatedAt <= filter.ToDate.Value);

            if (filter.MinPrice.HasValue)
                query = query.Where(o => o.Price >= filter.MinPrice.Value);

            if (filter.MaxPrice.HasValue)
                query = query.Where(o => o.Price <= filter.MaxPrice.Value);
        }

        query = ApplySorting(query, sort);

        var totalCount = query.Count();
        var items = query
            .Skip((pagination.Page - 1) * pagination.PageSize)
            .Take(pagination.PageSize)
            .ToList();

        return Task.FromResult(new PaginatedResult<TradeOrder>
        {
            Items = items,
            TotalCount = totalCount,
            Page = pagination.Page,
            PageSize = pagination.PageSize
        });
    }

