// Record Types
public record InventoryItem(
    int Id,
    string Sku,
    string Name,
    int Quantity,
    decimal UnitPrice,
    int WarehouseLocationId
);

public record WarehouseLocation(
    int Id,
    string Code,
    string Name,
    int Capacity
);

// Result Types for OneOf
public record ItemCreated(int Id, string Sku, string Name);
public record ItemUpdated(int Id, int NewQuantity);
public record ItemDeleted(int Id);
public record NotFound(int Id);
public record NotFoundBySku(string Sku);
public record ValidationError(string Message, string[] Errors);
public record Conflict(string Message);
public record LocationCreated(int Id, string Code);
public record LocationAtCapacity(int LocationId, int CurrentItems, int Capacity);

// Service Interface
public interface IInventoryService
{
    Task<OneOf<ItemCreated, ValidationError, Conflict>> CreateItemAsync(InventoryItem item);
    Task<OneOf<InventoryItem, NotFound>> GetItemByIdAsync(int id);
    Task<OneOf<InventoryItem, NotFoundBySku>> GetItemBySkuAsync(string sku);
    Task<OneOf<ItemUpdated, NotFound, ValidationError>> UpdateQuantityAsync(int id, int newQuantity);
    Task<OneOf<ItemDeleted, NotFound>> DeleteItemAsync(int id);
    Task<IEnumerable<InventoryItem>> GetAllItemsAsync();
