using FluentValidation;
using OneOf;
using System.ComponentModel.DataAnnotations;

// Command
public record TransferStockCommand(
    Guid SourceLocationId,
    Guid DestinationLocationId,
    Guid ProductId,
    int Quantity,
    string TransferReason
);

// Result Types
public record TransferSuccess(Guid TransferId, DateTime TransferredAt, int QuantityTransferred);
public record InsufficientStock(Guid ProductId, int CurrentStock, int RequestedQuantity);
public record LocationNotFound(Guid LocationId, string LocationType);
public record ValidationError(string[] Errors);

// Result Union
public readonly record struct TransferResult(OneOf<TransferSuccess, InsufficientStock, LocationNotFound, ValidationError> Value)
{
    public static implicit operator TransferResult(TransferSuccess success) => new(success);
    public static implicit operator TransferResult(InsufficientStock insufficient) => new(insufficient);
    public static implicit operator TransferResult(LocationNotFound notFound) => new(notFound);
    public static implicit operator TransferResult(ValidationError validation) => new(validation);
}

// Validator
public class TransferStockCommandValidator : AbstractValidator<TransferStockCommand>
{
    public TransferStockCommandValidator()
    {
        RuleFor(x => x.SourceLocationId)
            .NotEmpty()
            .WithMessage("Source location ID is required");

        RuleFor(x => x.DestinationLocationId)
            .NotEmpty()
            .WithMessage("Destination location ID is required")
            .NotEqual(x => x.SourceLocationId)
            .WithMessage("Source and destination locations must be different");

        RuleFor(x => x.ProductId)
            .NotEmpty()
            .WithMessage("Product ID is required");

        RuleFor(x => x.Quantity)
            .GreaterThan(0)
            .WithMessage("Quantity must be greater than 0");

        RuleFor(x => x.TransferReason)
            .NotEmpty()
            .WithMessage("Transfer reason is required")
            .MaximumLength(500)
            .WithMessage("Transfer reason cannot exceed 500 characters");
    }
}

// Service Interface
public interface IInventoryService
{
    Task<TransferResult> TransferStockAsync(TransferStockCommand command);
}

// Service Implementation
public class InventoryService : IInventoryService
{
    private readonly IStockRepository _stockRepository;
    private readonly ILocationRepository _locationRepository;

    public InventoryService(IStockRepository stockRepository, ILocationRepository locationRepository)
    {
        _stockRepository = stockRepository;
        _locationRepository = locationRepository;
    }

    public async Task<TransferResult> TransferStockAsync(TransferStockCommand command)
    {
        var sourceExists = await _locationRepository.ExistsAsync(command.SourceLocationId);
        if (!sourceExists)
            return new LocationNotFound(command.SourceLocationId, "Source");

        var destExists = await _locationRepository.ExistsAsync(command.DestinationLocationId);
        if (!destExists)
            return new LocationNotFound(command.DestinationLocationId, "Destination");

        var currentStock = await _stockRepository.GetStockAsync(command.SourceLocationId, command.ProductId);
        if (currentStock < command.Quantity)
            return new InsufficientStock(command.ProductId, currentStock, command.Quantity);

        var transferId = Guid.NewGuid();
        await _stockRepository.TransferAsync(
            command.SourceLocationId,
            command.DestinationLocationId,
            command.ProductId,
            command.Quantity);

        return new TransferSuccess(transferId, DateTime.UtcNow, command.Quantity);
    }
}

