// Service Interface
public interface IEmployeeOnboardingService
{
    Task<PagedResult<OnboardingSummary>> GetOnboardingsAsync(OnboardingQueryParameters parameters);
    Task<EmployeeOnboarding?> GetOnboardingByIdAsync(Guid id);
    Task<EmployeeOnboarding> CreateOnboardingAsync(CreateOnboardingRequest request);
    Task<EmployeeOnboarding?> UpdateOnboardingAsync(Guid id, UpdateOnboardingRequest request);
    Task<bool> DeleteOnboardingAsync(Guid id);
    Task<OnboardingTask?> AddTaskAsync(Guid onboardingId, CreateTaskRequest request);
    Task<OnboardingTask?> UpdateTaskAsync(Guid onboardingId, Guid taskId, UpdateTaskRequest request);
    Task<bool> DeleteTaskAsync(Guid onboardingId, Guid taskId);
