// Service Implementation
public class EmployeeOnboardingService : IEmployeeOnboardingService
{
    private readonly Dictionary<Guid, EmployeeOnboarding> _storage = new();

    public Task<PagedResult<OnboardingSummary>> GetOnboardingsAsync(OnboardingQueryParameters parameters)
    {
        var query = _storage.Values.AsQueryable();

        // Apply filters
        if (!string.IsNullOrWhiteSpace(parameters.SearchTerm))
        {
            var term = parameters.SearchTerm.ToLowerInvariant();
            query = query.Where(x =>
                x.FirstName.ToLower().Contains(term) ||
                x.LastName.ToLower().Contains(term) ||
                x.Email.ToLower().Contains(term) ||
                x.Position.ToLower().Contains(term));
        }

        if (parameters.Status.HasValue)
        {
            query = query.Where(x => x.Status == parameters.Status.Value);
        }

        if (!string.IsNullOrWhiteSpace(parameters.Department))
        {
            query = query.Where(x => x.Department.Equals(parameters.Department, StringComparison.OrdinalIgnoreCase));
        }

        if (parameters.StartDateFrom.HasValue)
        {
            query = query.Where(x => x.StartDate >= parameters.StartDateFrom.Value);
        }

        if (parameters.StartDateTo.HasValue)
        {
            query = query.Where(x => x.StartDate <= parameters.StartDateTo.Value);
        }

        // Apply sorting
        var sortBy = parameters.SortBy?.ToLowerInvariant() ?? "createdat";
        var descending = parameters.SortOrder?.Equals("desc", StringComparison.OrdinalIgnoreCase) ?? false;

        query = sortBy switch
        {
            "firstname" => descending ? query.OrderByDescending(x => x.FirstName) : query.OrderBy(x => x.FirstName),
            "lastname" => descending ? query.OrderByDescending(x => x.LastName) : query.OrderBy(x => x.LastName),
            "email" => descending ? query.OrderByDescending(x => x.Email) : query.OrderBy(x => x.Email),
            "department" => descending ? query.OrderByDescending(x => x.Department) : query.OrderBy(x => x.Department),
            "startdate" => descending ? query.OrderByDescending(x => x.StartDate) : query.OrderBy(x => x.StartDate),
            "status" => descending ? query.OrderByDescending(x => x.Status) : query.OrderBy(x => x.Status),
            "progresspercentage" => descending ? query.OrderByDescending(x => x.ProgressPercentage) : query.OrderBy(x => x.ProgressPercentage),
            _ => descending ? query.OrderByDescending(x => x.CreatedAt) : query.OrderBy(x => x.CreatedAt)
        };

        var totalCount = query.Count();

        var items = query
            .Skip((parameters.PageNumber - 1) * parameters.PageSize)
            .Take(parameters.PageSize)
            .Select(x => new OnboardingSummary
            {
                Id = x.Id,
                FirstName = x.FirstName,
                LastName = x.LastName,
                Email = x.Email,
                Department = x.Department,
                Position = x.Position,
                Status = x.Status,
                ProgressPercentage = x.ProgressPercentage,
                StartDate = x.StartDate,
                AssignedMentorId = x.AssignedMentorId,
                TotalTasks = x.Tasks.Count,
                CompletedTasks = x.Tasks.Count(t => t.IsCompleted)
            })
            .ToList();

        return Task.FromResult(new PagedResult<OnboardingSummary>
        {
            Items = items,
            TotalCount = totalCount,
            PageNumber = parameters.PageNumber,
            PageSize = parameters.PageSize
        });
    }

    public Task<EmployeeOnboarding?> GetOnboardingByIdAsync(Guid id)
    {
        _storage.TryGetValue(id, out var onboarding);
        return Task.FromResult(onboarding);
    }

    public Task<EmployeeOnboarding> CreateOnboardingAsync(CreateOnboardingRequest request)
    {
        var id = Guid.NewGuid();
        var now = DateTimeOffset.UtcNow;

        var tasks = request.Tasks?.Select((t, index) => new OnboardingTask
        {
            Id = Guid.NewGuid(),
            Title = t.Title,
            Description = t.Description,
            IsCompleted = false,
            Order = t.Order > 0 ? t.Order : index,
            DueDate = t.DueDate
        }).ToList() ?? new List<OnboardingTask>();

        var onboarding = new EmployeeOnboarding
        {
            Id = id,
            FirstName = request.FirstName,
            LastName = request.LastName,
            Email = request.Email,
            Department = request.Department,
            Position = request.Position,
            StartDate = request.StartDate,
            Status = OnboardingStatus.Pending,
            ProgressPercentage = 0,
            AssignedMentorId = request.AssignedMentorId,
            Tasks = tasks,
            CreatedAt = now
        };

        _storage[id] = onboarding;
        return Task.FromResult(onboarding);
    }

    public Task<EmployeeOnboarding?> UpdateOnboardingAsync(Guid id, UpdateOnboardingRequest request)
    {
        if (!_storage.TryGetValue(id, out var existing))
        {
            return Task.FromResult<EmployeeOnboarding?>(null);
        }

        var updatedTasks = existing.Tasks;
        if (request.Tasks != null)
        {
            updatedTasks = request.Tasks.Select((t, index) =>
            {
                var existingTask = existing.Tasks.FirstOrDefault(x => x.Id == t.Id);
                return new OnboardingTask
                {
                    Id = t.Id ?? Guid.NewGuid(),
                    Title = t.Title ?? existingTask?.Title ?? string.Empty,
                    Description = t.Description ?? existingTask?.Description,
                    IsCompleted = t.IsCompleted ?? existingTask?.IsCompleted ?? false,
                    Order = t.Order ?? existingTask?.Order ?? index,
                    DueDate = t.DueDate ?? existingTask?.DueDate
                };
            }).ToList();
        }

        var progress = request.ProgressPercentage ?? existing.ProgressPercentage;
        var status = request.Status ?? existing.Status;

        if (progress == 100 && status != OnboardingStatus.Completed)
        {
            status = OnboardingStatus.Completed;
        }
        else if (progress > 0 && progress < 100 && status == OnboardingStatus.Pending)
        {
            status = OnboardingStatus.InProgress;
        }

        var updated = existing with
        {
            FirstName = request.FirstName ?? existing.FirstName,
            LastName = request.LastName ?? existing.LastName,
            Email = request.Email ?? existing.Email,
            Department = request.Department ?? existing.Department,
            Position = request.Position ?? existing.Position,
            StartDate = request.StartDate ?? existing.StartDate,
            Status = status,
            ProgressPercentage = progress,
            AssignedMentorId = request.AssignedMentorId ?? existing.AssignedMentorId,
            Tasks = updatedTasks,
            UpdatedAt = DateTimeOffset.UtcNow
        };

        _storage[id] = updated;
        return Task.FromResult<EmployeeOnboarding?>(updated);
    }

    public Task<bool> DeleteOnboardingAsync(Guid id)
    {
        return Task.FromResult(_storage.Remove(id));
    }

    public Task<OnboardingTask?> AddTaskAsync(Guid onboardingId, CreateTaskRequest request)
    {
        if (!_storage.TryGetValue(onboardingId, out var existing))
        {
            return Task.FromResult<OnboardingTask?>(null);
        }

        var task = new OnboardingTask
        {
            Id = Guid.NewGuid(),
            Title = request.Title,
            Description = request.Description,
            IsCompleted = false,
            Order = request.Order,
            DueDate = request.DueDate
        };

        var tasks = existing.Tasks.ToList();
        tasks.Add(task);

        var updated = existing with { Tasks = tasks, UpdatedAt = DateTimeOffset.UtcNow };
        _storage[onboardingId] = updated;

        return Task.FromResult<OnboardingTask?>(task);
    }

    public Task<OnboardingTask?> UpdateTaskAsync(Guid onboardingId, Guid taskId, UpdateTaskRequest request)
    {
        if (!_storage.TryGetValue(onboardingId, out var existing))
        {
            return Task.FromResult<OnboardingTask?>(null);
        }

        var taskIndex = -1;
        for (var i = 0; i < existing.Tasks.Count; i++)
        {
            if (existing.Tasks[i].Id == taskId)
            {
                taskIndex = i;
                break;
            }
        }

        if (taskIndex == -1)
        {
            return Task.FromResult<OnboardingTask?>(null);
        }

        var existingTask = existing.Tasks[taskIndex];
        var updatedTask = existingTask with
        {
            Title = request.Title ?? existingTask.Title,
            Description = request.Description ?? existingTask.Description,
            IsCompleted = request.IsCompleted ?? existingTask.IsCompleted,
            Order = request.Order ?? existingTask.Order,
            DueDate = request.DueDate ?? existingTask.DueDate
        };

        var tasks = existing.Tasks.ToList();
        tasks[taskIndex] = updatedTask;

        var completedCount = tasks.Count(t => t.IsCompleted);
        var progress = tasks.Count > 0 ? (int)Math.Round((double)completedCount / tasks.Count * 100) : 0;

        OnboardingStatus status = existing.Status;
        if (progress == 100 && existing.Status != OnboardingStatus.Completed)
        {
            status = OnboardingStatus.Completed;
        }
        else if (progress > 0 && existing.Status == OnboardingStatus.Pending)
        {
            status = OnboardingStatus.InProgress;
        }

        var updated = existing with
        {
            Tasks = tasks,
            ProgressPercentage = progress,
            Status = status,
            UpdatedAt = DateTimeOffset.UtcNow
        };

        _storage[onboardingId] = updated;

        return Task.FromResult<OnboardingTask?>(updatedTask);
    }

    public Task<bool> DeleteTaskAsync(Guid onboardingId, Guid taskId)
    {
        if (!_storage.TryGetValue(onboardingId, out var existing))
        {
            return Task.FromResult(false);
        }

        var tasks = existing.Tasks.ToList();
        var task = tasks.FirstOrDefault(t => t.Id == taskId);

        if (task == null)
        {
            return Task.FromResult(false);
        }

        tasks.Remove(task);

        var updated = existing with { Tasks = tasks, UpdatedAt = DateTimeOffset.UtcNow };
        _storage[onboardingId] = updated;

        return Task.FromResult(true);
    }
}

// Controller
[ApiController]
[Route("api/[controller]")]
public class EmployeeOnboardingController : ControllerBase
{
    private readonly IEmployeeOnboardingService _service;

    public EmployeeOnboardingController(IEmployeeOnboardingService service)
    {
        _service = service;
    }

    /// <summary

using System;
using System.Collections.Generic;
using System.ComponentModel.DataAnnotations;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Builder;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using OneOf;

var builder = WebApplication.CreateBuilder(args);

builder.Services.AddScoped<IEmployeeOnboardingService, EmployeeOnboardingService>();

var app = builder.Build();

app.MapPost("/employees/onboard", async (OnboardEmployeeCommand command, IEmployeeOnboardingService service) =>
{
    var validationResults = new List<ValidationResult>();
    var context = new ValidationContext(command);

    if (!Validator.TryValidateObject(command, context, validationResults, true))
    {
        var errors = new Dictionary<string, string[]>();
        foreach (var result in validationResults)
        {
            foreach (var memberName in result.MemberNames)
            {
                if (!errors.ContainsKey(memberName))
                    errors[memberName] = Array.Empty<string>();

                var existingErrors = new List<string>(errors[memberName]) { result.ErrorMessage };
                errors[memberName] = existingErrors.ToArray();
            }
        }
        return Results.ValidationProblem(errors);
    }

    var result = await service.OnboardEmployeeAsync(command);

    return result.Match<Microsoft.AspNetCore.Http.IResult>(
        success => Results.Created($"/employees/{success.EmployeeId}", success),
        notFound => Results.NotFound(notFound),
        error => Results.BadRequest(error)
    );
});

app.Run();

public record OnboardEmployeeCommand
{
    [Required(ErrorMessage = "EmployeeId is required")]
    public Guid EmployeeId { get; init; }

    [Required(ErrorMessage = "FirstName is required")]
    [StringLength(100, ErrorMessage = "FirstName cannot exceed 100 characters")]
    public string FirstName { get; init; } = string.Empty;

    [Required(ErrorMessage = "LastName is required")]
    [StringLength(100, ErrorMessage = "LastName cannot exceed 100 characters")]
    public string LastName { get; init; } = string.Empty;

    [Required(ErrorMessage = "Email is required")]
    [EmailAddress(ErrorMessage = "Email must be a valid email format")]
    public string Email { get; init; } = string.Empty;

    [Required(ErrorMessage = "Department is required")]
    [ValidDepartment]
    public string Department { get; init; } = string.Empty;

    [Required(ErrorMessage = "Position is required")]
    [StringLength(100, ErrorMessage = "Position cannot exceed 100 characters")]
    public string Position { get; init; } = string.Empty;

    [Required(ErrorMessage = "StartDate is required")]
    [FutureOrTodayDate]
    public DateTime StartDate { get; init; }

    [Range(30000, 500000, ErrorMessage = "Salary must be between 30000 and 500000")]
    public decimal Salary { get; init; }

    public OnboardEmployeeCommand(
        Guid employeeId,
        string firstName,
        string lastName,
        string email,
        string department,
        string position,
        DateTime startDate,
        decimal salary)
    {
        EmployeeId = employeeId;
        FirstName = firstName;
        LastName = lastName;
        Email = email;
        Department = department;
        Position = position;
        StartDate = startDate;
        Salary = salary;
    }
}

[AttributeUsage(AttributeTargets.Property, AllowMultiple = false)]
public class ValidDepartmentAttribute : ValidationAttribute
{
    private static readonly HashSet<string> ValidDepartments = new()
    {
        "Engineering", "Sales", "Marketing", "HR", "Finance"
    };

    protected override ValidationResult IsValid(object? value, ValidationContext validationContext)
    {
        if (value is string department && ValidDepartments.Contains(department))
        {
            return ValidationResult.Success!;
        }

        return new ValidationResult(
            "Department must be one of: Engineering, Sales, Marketing, HR, Finance",
            new[] { validationContext.MemberName! });
    }
}

[AttributeUsage(AttributeTargets.Property, AllowMultiple = false)]
public class FutureOrTodayDateAttribute : ValidationAttribute
{
    protected override ValidationResult IsValid(object? value, ValidationContext validationContext)
    {
        if (value is DateTime date && date.Date >= DateTime.Today)
        {
            return ValidationResult.Success!;
        }

        return new ValidationResult(
            "StartDate must be today or in the future",
            new[] { validationContext.MemberName! });
    }
}

public record OnboardingSuccess(Guid EmployeeId, string Message);
public record NotFound(string Reason);
public record Error(string Code, string Description);

public interface IEmployeeOnboardingService
{
    Task<OneOf<OnboardingSuccess, NotFound, Error>> OnboardEmployeeAsync(OnboardEmployeeCommand command);
}

public class EmployeeOnboardingService : IEmployeeOnboardingService
{
    private readonly HashSet<Guid> _existingEmployees = new();

    public Task<OneOf<OnboardingSuccess, NotFound, Error>> OnboardEmployeeAsync(OnboardEmployeeCommand command)
    {
        if (command.EmployeeId == Guid.Empty)
        {
            return Task.FromResult<OneOf<OnboardingSuccess, NotFound, Error>>(
                new Error("INVALID_ID", "EmployeeId must not be empty"));
        }

        if (_existingEmployees.Contains(command.EmployeeId))
        {
            return Task.FromResult<OneOf<OnboardingSuccess, NotFound, Error>>(
                new Error("DUPLICATE", "Employee already exists"));
        }

        _existingEmployees.Add(command.EmployeeId);

        return Task.FromResult<OneOf<OnboardingSuccess, NotFound, Error>>(
            new OnboardingSuccess(command.EmployeeId, $"Employee {command.FirstName} {command.LastName} onboarded successfully to {command.Department}"));
    }
}
